//! Ed25519 detached-signature verification for library bundles.
//!
//! The public key is baked into the binary. Rotating it requires a recompile,
//! which is intentional — the key lifecycle is tied to release cadence, not
//! runtime configuration. The private key lives offline (see
//! `tools/sign-library-bundle/README.md`).

use ed25519_dalek::{Signature, Verifier, VerifyingKey};

use crate::error::{AppError, AppResult};

/// Ed25519 public key used to verify shipped library bundles.
///
/// Generated by `sign-library-bundle keygen`. To rotate:
///   1. Run `sign-library-bundle keygen --out <dir>` on the signing host.
///   2. Replace these bytes with the new public key's raw bytes.
///   3. Re-sign all bundles shipped with the release under the new key.
pub const LIBRARY_PUBLIC_KEY: [u8; 32] = [
    0x09, 0x64, 0xb2, 0x22, 0x8e, 0x5e, 0x45, 0xc6, 0x7a, 0x8e, 0x7a, 0xe8, 0x70, 0xa7, 0x7d, 0x25,
    0xb2, 0xb4, 0x6f, 0x27, 0x5b, 0xc0, 0xbe, 0xaa, 0x65, 0x08, 0x04, 0x14, 0xbc, 0x22, 0x37, 0xd9,
];

/// Verify a detached Ed25519 signature (hex-encoded) over `bundle_bytes`.
pub fn verify_bundle(bundle_bytes: &[u8], signature_hex: &str) -> AppResult<()> {
    let vk = VerifyingKey::from_bytes(&LIBRARY_PUBLIC_KEY)
        .map_err(|e| AppError::Crypto(format!("library public key invalid: {e}")))?;

    let sig_bytes = hex::decode(signature_hex.trim())
        .map_err(|e| AppError::Crypto(format!("library signature hex decode: {e}")))?;
    let sig_array: [u8; 64] = sig_bytes
        .as_slice()
        .try_into()
        .map_err(|_| AppError::Crypto("library signature must be 64 bytes".into()))?;
    let sig = Signature::from_bytes(&sig_array);

    vk.verify(bundle_bytes, &sig)
        .map_err(|_| AppError::Crypto("library bundle signature invalid".into()))?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use ed25519_dalek::{Signer, SigningKey};

    #[test]
    fn rejects_tampered_bundle() {
        // Sign a payload with a deterministic throwaway key, mutate it,
        // confirm rejection. Uses `from_bytes` instead of `generate` so the
        // app crate does not need to pull in `rand_core` at runtime — key
        // generation belongs to the offline signing tool.
        let sk = SigningKey::from_bytes(&[7u8; 32]);
        let payload = b"hello library";
        let sig = sk.sign(payload);

        let vk = sk.verifying_key();
        assert!(vk.verify(payload, &sig).is_ok());

        let mut tampered = payload.to_vec();
        tampered[0] ^= 1;
        assert!(vk.verify(&tampered, &sig).is_err());
    }

    #[test]
    fn baked_public_key_is_valid_point() {
        // Guards against a typo when the key was hand-copied from the keygen
        // output. An invalid point would crash the verifier on first bundle
        // load at runtime; this catches it at `cargo test` time.
        VerifyingKey::from_bytes(&LIBRARY_PUBLIC_KEY)
            .expect("baked LIBRARY_PUBLIC_KEY must be a valid Ed25519 point");
    }
}
